function About() {
  return (
    <div className="hero">
      <h1>About Community Help Hub</h1>

      <p>
        Community Help Hub is a platform designed to connect people who need help
        with volunteers and community members who can offer support.
      </p>

      <p>
        Our goal is to create a supportive environment where everyone can share
        skills, services, and kindness.
      </p>
    </div>
  );
}

export default About;
